```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Return error if connection fails
  }
  auto conn = *conn_result;

  // Begin transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return -1;
  }

  // Execute the delete operation with condition
  auto delete_result = conn->execute(
      sqlgen::delete_from<User> | sqlgen::where("last_login"_c < sqlgen::date("2025-01-01")))
  );

  if (!delete_result) {
    return -1;
  }

  // Commit the transaction
  auto commit_result = conn->commit();
  return commit_result ? 0 : -1;
}

} // namespace delete_inactive_users
```

