#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  auto result = conn->begin_transaction();
  if (!result) {
    return false;
  }

  auto query1 = sqlgen::update<Account> 
               | sqlgen::set("balance"_c = "balance"_c - amount)
               | sqlgen::where("account_id"_c == from_account_id && "balance"_c >= amount);

  auto result1 = conn->execute(query1, amount, from_account_id, amount);
  if (result1.is_error() || result1.rows_affected != 1) {
    conn->rollback();
    return false;
  }

  auto query2 = sqlgen::update<Account> 
               | sqlgen::set("balance"_c = "balance"_c + amount)
               | sqlgen::where("account_id"_c == to_account_id);

  auto result2 = conn->execute(query2, amount, to_account_id);
  if (result2.is_error() || result2.rows_affected != 1) {
    conn->rollback();
    return false;
  }

  result = conn->commit();
  if (!result) {
    conn->rollback();
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds

