```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace generate_sql_dry_run {

struct A {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct B {
  sqlgen::PrimaryKey<int> id;
  int a_id;
  double score;
};

std::string generate_sql_dry_run() {
    using namespace sqlgen::literals;

    auto query = sqlgen::select_from<A>("a")
        .join<B>("b", "a.id" == "b.a_id")
        .where("b.score"_c > 10 && "a.name"_c.contains("x"))
        .order_by("b.score"_c, "a.id"_c.desc())
        .limit(5);

    return sqlgen::sqlite::to_sql(query);
}

}  // namespace generate_sql_dry_run
```

**Explanation:**

1. **Query Construction:**
   - `sqlgen::select_from<A>("a")`: Creates a SELECT query on table A with alias "a"
   - `.join<B>("b", "a.id" == "b.a_id")`: Joins table B with alias "b" on the condition that A.id equals B.a_id
   - `.where("b.score"_c > 10 && "a.name"_c.contains("x"))`: Applies WHERE clause with compound condition
   - `.order_by("b.score"_c, "a.id"_c.desc())`: Orders by B.score ascending and A.id descending
   - `.limit(5)`: Limits results to 5 records

2. **SQL Generation:**
   - `sqlgen::sqlite::to_sql(query)` converts the constructed query object into a SQL string for SQLite

3. **Return Value:**
   - The function returns the generated SQL string as required

The generated SQL will look something like:
```sql
SELECT a.id, a.name, b.id, b.a_id, b.score 
FROM A AS a 
JOIN B AS b ON a.id = b.a_id 
WHERE b.score > 10 AND a.name LIKE '%x%' 
ORDER BY b.score ASC, a.id DESC 
LIMIT 5
```

